import{_ as a,c as o,m as e,a as r,t as c,U as s,o as d}from"./chunks/framework.9QHaLlVJ.js";const i="/assets/image-20211118180155887.KiEzCZpn.png",P=JSON.parse('{"title":"大端小端","description":"","frontmatter":{"title":"大端小端"},"headers":[],"relativePath":"doc/编程语言/汇编/基础/大端小端/大端小端.md","filePath":"packages/doc/src/编程语言/汇编/基础/大端小端/大端小端.md","lastUpdated":1705850916000}'),p={name:"doc/编程语言/汇编/基础/大端小端/大端小端.md"},n={id:"frontmatter-title",tabindex:"-1"},_=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),l=s('<h2 id="为什么有大小端之分" tabindex="-1">为什么有大小端之分 <a class="header-anchor" href="#为什么有大小端之分" aria-label="Permalink to &quot;为什么有大小端之分&quot;">​</a></h2><p>我一直都不理解，为什么要有大小端区分，尤其是小端，总是会忘记，因为他不符合人类的思维习惯，但存在即为合理，存在就有他存在的价值。这里有一个比较合理的解释：计算机中电路优先处理低位字节，效率比较高，因为计算机都是从低位开始的，所以计算机内部处理都是小端字节序。但是我们平常读写数值的方法，习惯用大端字节序，所以除了计算机的内部，其他场景大都是大端字节序，比如：网络传输和文件储存时都是用的大端字节序。</p><p>所以大小端问题很可能与硬件或者软件的创造者们有关，实际在计算机工业应用上，不同的操作系统和不同的芯片类型都有所不同。不同的系统设计不同，所以我们也没必要深究为什么要有这个区分，只需要知道他们的原理就好了。</p><h2 id="什么是大端、小端" tabindex="-1">什么是大端、小端 <a class="header-anchor" href="#什么是大端、小端" aria-label="Permalink to &quot;什么是大端、小端&quot;">​</a></h2><p>大端模式：高位字节排放在内存的低地址端，低位字节排放在内存的高地址端;</p><p>小端模式：低位字节排放在内存的低地址端，高位字节排放在内存的高地址端；</p><p>这么说也有点模糊，还是配个图来看更清晰：</p><p>我们来看一看数值<code>0x1A2B3C4D</code>在大端与小端的表现形式，这里我们假设地址是从<code>0x4000</code>开始：</p><p><img src="'+i+'" alt="image-20211118180155887">上图所示：大端和小端的字节序最小单位是1字节(8bit)，大端字节序就和我们平时的写法顺序一样，从低地址到高地址写入<code>0x1A2B3C4D</code>，而小端字节序就是我们平时的写法反过来，因为字节序最小单位为<code>1</code>字节，所以从低地址到高地址写入<code>0x4D3C2B1A</code>。</p><p>因为大端、小端很容易混记，所以分享一个我自己记忆的小技巧：</p><p>大端：高低高低，也就是高位字节排放在内存低地址端，高地址端存在低位字节；</p><p>小端：高高低低；也就是高位字节排放在内存的高地址端，低位字节排放在内存的低地址端；</p>',12);function h(t,m,f,x,u,b){return d(),o("div",null,[e("h1",n,[r(c(t.$frontmatter.title)+" ",1),_]),l])}const T=a(p,[["render",h]]);export{P as __pageData,T as default};
